def ser_int(v):
    return f'num:{v}'

def ser_str(v):
    return f'str:{v}'

def ser_bool(v):
    return f'bool:{v}'

serializers = {int: ser_int, str: ser_str, bool: ser_bool}

def serialize(value):
    fn = serializers.get(type(value))
    return fn(value) if fn else f'raw:{value}'

print(serialize(42))
print(serialize('hello'))
